import { useCallback } from 'react';

import type { Point } from '../../../types/point.js';
import { useCanvas } from '../hooks/useCanvas.js';

interface RectClipPathCanvasProps {
  height: number;
  width: number;
  position: Point;
}

export const RectClipPathCanvas = (props: RectClipPathCanvasProps) => {
  const { height, width, position } = props;

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D) => {
      const { x, y } = position;
      const xMax = x + width - 1;
      const yMax = y + height - 1;

      ctx.save();
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(xMax, y);
      ctx.lineTo(xMax, yMax);
      ctx.lineTo(x, yMax);
      ctx.lineTo(x, y);
      ctx.clip();

      return false;
    },
    [height, width, position],
  );

  useCanvas('rect-clip-path', draw);

  return null;
};
